it('Append text to a pad Id', async function () {
  let res = await agent.get(
      `${endPoint('appendText', '1.2.13')}?padID=${testPadId}&text=hello`)
      .set("Authorization", (await common.generateJWTToken()))
      .expect(200)
      .expect('Content-Type', /json/);
