  await agent.get(`${endPoint('createPad')}?padID=${padId}`)
      .set("Authorization", (await common.generateJWTToken()));
  await agent.post(endPoint('setHTML'))
      .set("Authorization", (await common.generateJWTToken()))
      .send({
